//
// fedmeetup is the federated-meetup host daemon. It serves the open
// ConnectRPC API, MCP discovery endpoints, and the server-rendered web
// UI — all on a single port.
//
// The ConnectRPC handler is GENERATED by protoc-gen-connect-go. The web
// UI, MCP server, and discovery endpoints are wired in alongside it.
//
// Default: in-memory protocol state. Persistence is opt-in via
// HOSTD_PROTOCOL_DB. SQLite for web cache/RSVPs/sessions, SMTP
// for email delivery.
//     The group identity comes from env config. Protocol state persistence
//     is opt-in via HOSTD_PROTOCOL_DB — when set, all transitions are
//     persisted to a SQLite log and replayed on restart.
//
// v0 config (all from env):
//   HOSTD_ADDR         listen address (default ":8080")
//   HOSTD_GROUP_KEY    hex-encoded 32-byte group public key (required)
//   HOSTD_NAME         canonical name this host advertises (default "hostd")
//   HOSTD_STEWARDS     comma-separated hex keys (initial stewards; parsed but unused)
//   HOSTD_THRESHOLD    initial threshold (default 0)
//   HOSTD_BASE_URL     public base URL for absolute links/JSON-LD (e.g. "https://fm.scoble.me")
//   HOSTD_DB_PATH      SQLite path for web store (default "fedmeetup.db")
//   HOSTD_DESCRIPTION  host description for discovery endpoints
//   HOSTD_AREA         geographic area for discovery (e.g. "Las Vegas, NV")
//   HOSTD_PROTOCOL_DB  SQLite path for protocol transition log (default: empty = in-memory)
//   HOSTD_SMTP_HOST    SMTP server hostname (default: empty = log-only email)
//   HOSTD_SMTP_PORT    SMTP server port (default "587")
//   HOSTD_SMTP_USER    SMTP username
//   HOSTD_SMTP_PASS    SMTP password
//   HOSTD_SMTP_FROM    From email address
//   STRIPE_SECRET_KEY       Stripe API key (default: empty = mock payments)
//   STRIPE_WEBHOOK_SECRET   Stripe webhook signing secret
//
// Federation sync (optional — omit to run standalone):
//   HOSTD_PEERS        comma-separated peer URLs to sync from (e.g. "http://peer:8080")
//   HOSTD_SYNC_BOOTSTRAP  if "true" (default), bootstrap from peers on startup
//   HOSTD_SYNC_LIVE    if "true" (default), maintain live Subscribe streams after bootstrap
//
// ActivityPub federation:
//   GET  /.well-known/webfinger       — account discovery
//   GET  /ap/actor/{name}             — group actor document
//   GET  /ap/outbox/{name}            — Create/Event activities
//   POST /ap/inbox/{name}             — Follow/Undo from remote servers
package main

import (
	"context"
	"encoding/hex"
	"errors"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/signal"
	"strconv"
	"strings"
	"syscall"
	"time"

	"github.com/sscoble/federated-meetup/proto/federated_meetup/v1/federatedmeetupv1connect"

	"github.com/sscoble/federated-meetup/internal/activitypub"
	"github.com/sscoble/federated-meetup/internal/email"
	"github.com/sscoble/federated-meetup/internal/federation"
	"github.com/sscoble/federated-meetup/internal/group"
	"github.com/sscoble/federated-meetup/internal/host"
	"github.com/sscoble/federated-meetup/internal/mcp"
	"github.com/sscoble/federated-meetup/internal/payment"
	"github.com/sscoble/federated-meetup/internal/product"
	"github.com/sscoble/federated-meetup/internal/types"
	"github.com/sscoble/federated-meetup/internal/web"
)

// config holds the runtime configuration of fedmeetup. All values come
// from environment variables (see package doc).
type config struct {
	addr        string
	groupKey    types.PublicKey
	name        string
	threshold   uint32
	baseURL     string
	dbPath      string
	description string
	area        string
	peers       []string
	syncBootstrap bool
	syncLive    bool
	protocolDB  string
	// SMTP / email
	smtpHost    string
	smtpPort    string
	smtpUser    string
	smtpPass    string
	smtpFrom    string
}

func loadConfig() (*config, error) {
	cfg := &config{
		addr:        getEnv("HOSTD_ADDR", ":8080"),
		name:        getEnv("HOSTD_NAME", "hostd"),
		baseURL:     getEnv("HOSTD_BASE_URL", "http://localhost:8080"),
		dbPath:      getEnv("HOSTD_DB_PATH", "fedmeetup.db"),
		description: getEnv("HOSTD_DESCRIPTION", "Federated Meetup host"),
		area:        getEnv("HOSTD_AREA", ""),
	}

	gkHex := os.Getenv("HOSTD_GROUP_KEY")
	if gkHex == "" {
		return nil, errors.New("HOSTD_GROUP_KEY is required (hex 32 bytes)")
	}
	gkBytes, err := hex.DecodeString(strings.TrimPrefix(gkHex, "0x"))
	if err != nil {
		return nil, fmt.Errorf("HOSTD_GROUP_KEY: %w", err)
	}
	if len(gkBytes) != 32 {
		return nil, fmt.Errorf("HOSTD_GROUP_KEY: got %d bytes, want 32", len(gkBytes))
	}
	copy(cfg.groupKey[:], gkBytes)

	if t := os.Getenv("HOSTD_THRESHOLD"); t != "" {
		v, err := strconv.ParseUint(t, 10, 32)
		if err != nil {
			return nil, fmt.Errorf("HOSTD_THRESHOLD: %w", err)
		}
		cfg.threshold = uint32(v)
	}
	_ = os.Getenv("HOSTD_STEWARDS") // parsed but unused — stewards are added via ADD_STEWARD transitions

	// Federation sync config.
	cfg.syncBootstrap = getEnv("HOSTD_SYNC_BOOTSTRAP", "true") == "true"
	cfg.syncLive = getEnv("HOSTD_SYNC_LIVE", "true") == "true"
	if peers := os.Getenv("HOSTD_PEERS"); peers != "" {
		for _, p := range strings.Split(peers, ",") {
			p = strings.TrimSpace(p)
			if p != "" {
				cfg.peers = append(cfg.peers, p)
			}
		}
	}

	// Protocol state persistence (opt-in).
	// If HOSTD_PROTOCOL_DB is set, transitions are persisted to a
	// SQLite database at that path and replayed on startup.
	cfg.protocolDB = os.Getenv("HOSTD_PROTOCOL_DB")

	// SMTP / email config.
	cfg.smtpHost = os.Getenv("HOSTD_SMTP_HOST")
	cfg.smtpPort = getEnv("HOSTD_SMTP_PORT", "587")
	cfg.smtpUser = os.Getenv("HOSTD_SMTP_USER")
	cfg.smtpPass = os.Getenv("HOSTD_SMTP_PASS")
	cfg.smtpFrom = os.Getenv("HOSTD_SMTP_FROM")

	return cfg, nil
}

func getEnv(k, def string) string {
	if v := os.Getenv(k); v != "" {
		return v
	}
	return def
}

func main() {
	cfg, err := loadConfig()
	if err != nil {
		log.Fatalf("config: %v", err)
	}

	// ---- Protocol layer (ConnectRPC) ----
	// If HOSTD_PROTOCOL_DB is set, create a SQLite persister and
	// replay all stored transitions on startup. Otherwise, the state
	// is entirely in-memory (backward compatible).
	var state *group.State
	if cfg.protocolDB != "" {
		persisterDSN := fmt.Sprintf("file:%s?_journal_mode=WAL&_busy_timeout=5000", cfg.protocolDB)
		persister, err := group.NewSQLitePersister(persisterDSN, cfg.groupKey)
		if err != nil {
			log.Fatalf("protocol persister: %v", err)
		}
		defer persister.Close()
		state, err = group.NewStateWithPersister(cfg.groupKey, persister)
		if err != nil {
			log.Fatalf("protocol state (replay): %v", err)
		}
		log.Printf("fedmeetup: replayed %d transitions from %s, root=0x%x",
			state.TransitionCount(), cfg.protocolDB, state.Root())
	} else {
		state = group.NewState(cfg.groupKey)
	}
	svc := host.NewService(cfg.name, state)

	// ---- Product layer (ticketing, orders, auth) ----
	prodStore := product.NewStore()
	var paySvc payment.Provider
	if payment.HasStripeKey() {
		successURL := cfg.baseURL + "/checkout/success"
		cancelURL := cfg.baseURL + "/checkout/cancel"
		paySvc = payment.NewStripeConnectProvider(successURL, cancelURL)
		log.Printf("fedmeetup: Stripe payments enabled (checkout success=%s)", successURL)
	} else {
		paySvc = payment.NewMockProvider()
		log.Printf("fedmeetup: Stripe not configured (STRIPE_SECRET_KEY unset) — using mock payments")
	}
	prodSvc := product.NewService(prodStore, paySvc)

	// ---- Web layer (HTMX + SQLite) ----
	dsn := fmt.Sprintf("file:%s?_journal_mode=WAL&_busy_timeout=5000", cfg.dbPath)
	webStore, err := web.NewStore(dsn)
	if err != nil {
		log.Fatalf("web store: %v", err)
	}
	defer webStore.Close()

	// Email sender: SMTP if configured, log-only for dev.
	var emailSender email.EmailSender
	if cfg.smtpHost != "" {
		emailSender = email.NewSMTPSender(email.SMTPConfig{
			Host:     cfg.smtpHost,
			Port:     cfg.smtpPort,
			Username: cfg.smtpUser,
			Password: cfg.smtpPass,
			From:     cfg.smtpFrom,
		})
		log.Printf("fedmeetup: SMTP email enabled (host=%s:%s, from=%s)", cfg.smtpHost, cfg.smtpPort, cfg.smtpFrom)
	} else {
		emailSender = email.NewLogOnlySender()
		log.Printf("fedmeetup: email in log-only mode (set HOSTD_SMTP_HOST to enable SMTP)")
	}

	webSrv, err := web.NewServer(svc, prodSvc, webStore, emailSender, cfg.baseURL)
	if err != nil {
		log.Fatalf("web server: %v", err)
	}

	// Seed demo data if the product store is empty (idempotent).
	webSrv.SeedData()

	// Register group canonical names with the host's name directory
	// so ResolveName can map canonical_name → group_key.
	for _, g := range prodStore.ListGroups() {
		svc.Groups().RegisterName(g.CanonicalName, cfg.groupKey)
	}

	// ---- MCP discovery layer ----
	mcpCfg := mcp.HostConfig{
		Name:           cfg.name,
		URL:            cfg.baseURL,
		Description:    cfg.description,
		GeographicArea: cfg.area,
	}

	// ---- Single mux: ConnectRPC + MCP + discovery + web UI ----
	mux := http.NewServeMux()

	// ConnectRPC
	rpcPath, rpcHandler := federatedmeetupv1connect.NewHostServiceHandler(svc)
	mux.Handle(rpcPath, rpcHandler)

	// MCP + discovery endpoints
	mcp.RegisterEndpoints(mux, svc, mcpCfg)

	// ActivityPub federation (WebFinger, actor, outbox, inbox)
	apAdapter := activitypub.NewProductStoreAdapter(prodStore)
	apSvc := activitypub.NewActivityPubService(cfg.baseURL, apAdapter)
	apSvc.RegisterRoutes(mux)
	log.Printf("fedmeetup: ActivityPub endpoints enabled (WebFinger, actor, outbox, inbox)")

	// Web UI (all routes: /, /groups/, /events/, /dashboard/, /rsvp/, /checkout/, /static/)
	mux.Handle("/", webSrv.Routes())

	// Stripe webhook endpoint
	stripeWebhook := prodStore.WebhookHandler("")
	mux.Handle("/webhook/stripe", stripeWebhook)

	// Health + identity (protocol ops)
	mux.HandleFunc("/healthz", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte("ok\n"))
	})
	mux.HandleFunc("/identity", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("content-type", "application/json")
		fmt.Fprintf(w, `{"group_key":"0x%s","name":%q,"threshold":%d}`+"\n",
			hex.EncodeToString(cfg.groupKey[:]), cfg.name, cfg.threshold)
	})

	srv := &http.Server{
		Addr:              cfg.addr,
		Handler:           mux,
		ReadHeaderTimeout: 5 * time.Second,
		// ConnectRPC uses HTTP/2; net/http auto-negotiates with TLS.
		// For v0 we serve plaintext HTTP/1.1; TLS termination is a
		// deployment concern (fronted by a reverse proxy or added in
		// cycle 72+).
	}

	idleConnsClosed := make(chan struct{})
	go func() {
		sigint := make(chan os.Signal, 1)
		signal.Notify(sigint, os.Interrupt, syscall.SIGTERM)
		<-sigint

		log.Printf("shutdown: draining connections for up to 10s")
		ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
		defer cancel()
		if err := srv.Shutdown(ctx); err != nil {
			log.Printf("shutdown: %v", err)
		}
		close(idleConnsClosed)
	}()

	log.Printf("fedmeetup: listening on %s, group_key=0x%s, name=%q, threshold=%d, mount=%s",
		cfg.addr, hex.EncodeToString(cfg.groupKey[:]), cfg.name, cfg.threshold, rpcPath)
	log.Printf("fedmeetup: HostService=%s", federatedmeetupv1connect.HostServiceName)
	log.Printf("fedmeetup: web UI at %s, base_url=%s, db=%s", cfg.addr, cfg.baseURL, cfg.dbPath)

	// ---- Federation sync (optional) ----
	// If HOSTD_PEERS is set, create a Syncer per peer and bootstrap
	// + live-stream from each. This makes this host a mirror of the
	// group state from the peer's perspective.
	if len(cfg.peers) > 0 {
		syncCtx, syncCancel := context.WithCancel(context.Background())
		defer syncCancel()

		for _, peerURL := range cfg.peers {
			peerURL := peerURL // capture for goroutine
			syncer := federation.NewSyncer(peerURL, cfg.groupKey, state, nil)

			if cfg.syncBootstrap {
				log.Printf("fedmeetup: bootstrapping from peer %s", peerURL)
				go func() {
					applied, err := syncer.Bootstrap(syncCtx)
					if err != nil {
						log.Printf("fedmeetup: bootstrap from %s failed: %v", peerURL, err)
						return
					}
					log.Printf("fedmeetup: bootstrap from %s complete (%d transitions applied, root=%x)",
						peerURL, applied, state.Root())
				}()
			}

			if cfg.syncLive {
				go func() {
					log.Printf("fedmeetup: live streaming from peer %s", peerURL)
					if err := syncer.Live(syncCtx); err != nil {
						log.Printf("fedmeetup: live stream from %s ended: %v", peerURL, err)
					}
				}()
			}
		}
		log.Printf("fedmeetup: federation sync active with %d peer(s)", len(cfg.peers))
	}

	// ---- Reminder scheduler ----
	// Every 15 minutes, check for events starting in ~24h and send
	// reminder emails to confirmed RSVPs.
	go startReminderScheduler(webStore, emailSender, cfg.baseURL)

	if err := srv.ListenAndServe(); err != nil && !errors.Is(err, http.ErrServerClosed) {
		log.Fatalf("listen: %v", err)
	}
	<-idleConnsClosed
	log.Printf("fedmeetup: stopped")
}
